import{_ as e,c as a,o as i,a2 as o}from"./chunks/framework.lHtoIQ2D.js";const u=JSON.parse('{"title":"CH01","description":"","frontmatter":{},"headers":[],"relativePath":"Study/infra-with-claude/ch-01.md","filePath":"Study/infra-with-claude/ch-01.md","lastUpdated":1782824424000}'),l={name:"Study/infra-with-claude/ch-01.md"};function r(p,t,s,d,c,n){return i(),a("div",null,t[0]||(t[0]=[o('<h1 id="ch01" tabindex="-1">CH01 <a class="header-anchor" href="#ch01" aria-label="Permalink to &quot;CH01&quot;">​</a></h1><blockquote><p>이 저장소는 「AI 시대에 개발자가 알아야 하는 인프라 구성 배포 with 클로드 코드」 책 스터디를 진행하며 정리한 내용을 다룹니다.</p></blockquote><h2 id="gitops에서-gitaiops로" tabindex="-1">GitOps에서 GitAIOps로 <a class="header-anchor" href="#gitops에서-gitaiops로" aria-label="Permalink to &quot;GitOps에서 GitAIOps로&quot;">​</a></h2><p>GitOps는 Git 저장소를 Single Source of Truth로 삼아, 인프라 상태를 선언적으로 관리하는 방법론을 의미한다.</p><p>전통적인 배포 방식은 명령형으로 누군가 어떤 명령어로 어떻게 작업하였는지 기록하기 어려움이 있었지만<br> GitOps는 Git 저장소(Ssot)를 통해 내가 원하는 자원의 상태를 선언하면 도구들이 그 상태를 맞추어 주는 방식이다.</p><ul><li>이게 가능한 이유는 쿠버네티스의 컨셉이 선언형 방식이기 때문이다</li></ul><p>GitAIOps는 이러한 GitOps에서 AI의 서포트를 받는 형식으로,</p><p>트러블 슈팅 기록, 매니패스트 작성 어시스턴트, 문서화 등 과 같은 작업을 함께한다.<br> 오래된 시스템일 수록 문서화가 중요한데 AI-Agent 를 통하여 작업과 동시에 문서화와 검증을 수행함으로써 같이 일할 수 있는 환경을 만들어 준다.</p><p>작업 내역들을 Git 커밋으로 상세히 기록할 경우 따로 문서화하지 않아도 나중에 돌아보면 커밋들만으로 이력을 뒤져볼 수 있다</p><h2 id="책의-구성과-실습-흐름" tabindex="-1">책의 구성과 실습 흐름 <a class="header-anchor" href="#책의-구성과-실습-흐름" aria-label="Permalink to &quot;책의 구성과 실습 흐름&quot;">​</a></h2><p>해당 책은 이론서가 아닌 실습 위주로 구성되어 있다.</p><ul><li>단순 이론만 적혀있는 것보단 실제 현업에서 생길만한 요구사항들을 적용해가면서 실습하는 것이 공부 흥미를 이끌어 준다. <ul><li>물론 부족한 이론 내용은 대충 넘기지 않고 채우는 것이 중요하다</li></ul></li></ul><p>GCP의 무료 크레딧을 통하여 GKE를 구성하고 챕터를 거듭하면서 가상의 <code>notiflex</code>라는 회사의 인프라를 성장시키는 흐름이다.</p><h2 id="실습-가드레일" tabindex="-1">실습 가드레일 <a class="header-anchor" href="#실습-가드레일" aria-label="Permalink to &quot;실습 가드레일&quot;">​</a></h2><p>책에서는 독자가 입력해야 할 명령어를 알려주지 않고 에이전트에게 전달할 자연어를 알려준다.</p><p>만약 사전에 준비된 가드레일이 없었더라면 독자마다 다른 방향으로 실습을 하게 될 것이다.</p><p><a href="https://github.com/sysnet4admin/_Book_GitAIOps" target="_blank" rel="noreferrer">https://github.com/sysnet4admin/_Book_GitAIOps</a> 책 실습 레포의 CLAUDE.md를 살펴보면 독자가 입력한 자연어와 최대한 관련된 항목의 참조파일을 찾아 수행한다.</p><ul><li><code>prompt-guardrails</code>: 실행 지침, 사전 조건, 진행 절차들의 명시됨</li><li><code>decision-guides</code>: 도구의 선택 근거</li><li><code>result-templates</code>: 체크리스트 검증, 실행 결과 확인</li></ul><p>이러한 사전 가드레일 덕분에 각 챕터마다 빠진 부분 없이 시나리오를 수행하고 제대로 가고 있는지 검증할 수 있다.</p>',19)]))}const _=e(l,[["render",r]]);export{u as __pageData,_ as default};
